  1	import * as React from 'react';
  2	import { connect } from 'react-redux';
  3	import { KialiDispatch } from 'types/Redux';
  4	import _ from 'lodash';
  5	import { kialiStyle } from 'styles/StyleUtils';
  6	import {
  7	  Button,
  8	  TextInput,
  9	  Tooltip,
 10	  Divider,
 11	  Badge,
 12	  Dropdown,
 13	  MenuToggleElement,
 14	  MenuToggle,
 15	  DropdownList,
 16	  Checkbox
 17	} from '@patternfly/react-core';
 18	import { KialiAppState } from '../../store/Store';
 19	import { activeNamespacesSelector, namespaceFilterSelector, namespaceItemsSelector } from '../../store/Selectors';
 20	import { NamespaceActions } from '../../actions/NamespaceAction';
 21	import { NamespaceThunkActions } from '../../actions/NamespaceThunkActions';
 22	import { Namespace } from '../../types/Namespace';
 23	import { HistoryManager, URLParam } from '../../app/History';
 24	import {
 25	  BoundingClientAwareComponent,
 26	  PropertyType
 27	} from '../BoundingClientAwareComponent/BoundingClientAwareComponent';
 28	import { KialiIcon } from 'config/KialiIcon';
 29	import { TourStop } from '../Tour/TourStop';
 30	import { GraphTourStops } from '../../pages/Graph/GraphHelpTour';
 31	
 32	interface ReduxStateProps {
 33	  activeNamespaces: Namespace[];
 34	  filter: string;
 35	  namespaces: Namespace[];
 36	}
 37	
 38	interface ReduxDispatchProps {
 39	  clearAll: () => void;
 40	  refresh: () => void;
 41	  setActiveNamespaces: (namespaces: Namespace[]) => void;
 42	  setFilter: (filter: string) => void;
 43	}
 44	
 45	type ReduxProps = ReduxStateProps & ReduxDispatchProps;
 46	
 47	type NamespaceDropdownProps = ReduxProps & {
 48	  disabled: boolean;
 49	};
 50	
 51	type NamespaceDropdownState = {
 52	  isBulkSelectorOpen: boolean;
 53	  isOpen: boolean;
 54	  selectedNamespaces: Namespace[];
 55	};
 56	
 57	const optionBulkStyle = kialiStyle({
 58	  marginLeft: '0.5rem',
 59	  position: 'relative',
 60	  top: 8
 61	});
 62	
 63	const optionStyle = kialiStyle({ marginLeft: '1.0rem' });
 64	
 65	const optionLabelStyle = kialiStyle({ marginLeft: '0.5rem' });
 66	
 67	const headerStyle = kialiStyle({
 68	  margin: '0.5rem',
 69	  marginTop: 0,
 70	  width: 300
 71	});
 72	
 73	const marginBottom = 20;
 74	
 75	const namespaceContainerStyle = kialiStyle({
 76	  overflow: 'auto'
 77	});
 78	
 79	const dividerStyle = kialiStyle({
 80	  paddingTop: '0.625rem'
 81	});
 82	
 83	const closeButtonStyle = kialiStyle({
 84	  borderTopLeftRadius: 0,
 85	  borderBottomLeftRadius: 0
 86	});
 87	
 88	class NamespaceDropdownComponent extends React.PureComponent<NamespaceDropdownProps, NamespaceDropdownState> {
 89	  constructor(props: NamespaceDropdownProps) {
 90	    super(props);
 91	    this.state = {
 92	      isBulkSelectorOpen: false,
 93	      isOpen: false,
 94	      selectedNamespaces: [...this.props.activeNamespaces]
 95	    };
 96	  }
 97	
 98	  componentDidMount(): void {
 99	    this.props.refresh();
100	    this.syncNamespacesURLParam();
101	  }
102	
103	  // update redux with URL namespaces if set, otherwise update URL with redux
104	  syncNamespacesURLParam = (): void => {
105	    const urlNamespaces = (HistoryManager.getParam(URLParam.NAMESPACES) || '').split(',').filter(Boolean);
106	    if (
107	      urlNamespaces.length > 0 &&
108	      _.difference(
109	        urlNamespaces,
110	        this.props.activeNamespaces.map(item => item.name)
111	      )
112	    ) {
113	      // We must change the props of namespaces
114	      const items = urlNamespaces.map(ns => ({ name: ns } as Namespace));
115	      this.props.setActiveNamespaces(items);
116	    } else if (urlNamespaces.length === 0 && this.props.activeNamespaces.length !== 0) {
117	      HistoryManager.setParam(URLParam.NAMESPACES, this.props.activeNamespaces.map(item => item.name).join(','));
118	    }
119	  };
120	
121	  componentDidUpdate(prevProps: NamespaceDropdownProps): void {
122	    if (prevProps.activeNamespaces !== this.props.activeNamespaces) {
123	      if (this.props.activeNamespaces.length === 0) {
124	        HistoryManager.deleteParam(URLParam.NAMESPACES);
125	      } else {
126	        HistoryManager.setParam(URLParam.NAMESPACES, this.props.activeNamespaces.map(item => item.name).join(','));
127	      }
128	      this.setState({ selectedNamespaces: this.props.activeNamespaces });
129	    }
130	  }
131	
132	  private namespaceButtonText(): JSX.Element {
133	    if (this.state.selectedNamespaces.length === 0) {
134	      return <span>Select Namespaces</span>;
135	    }
136	
137	    return (
138	      <>
139	        <span style={{ paddingRight: '0.75rem' }}>Namespace:</span>
140	        {this.state.selectedNamespaces.length === 1 ? (
141	          <span>{this.state.selectedNamespaces[0].name}</span>
142	        ) : (
143	          <Badge>{this.state.selectedNamespaces.length}</Badge>
144	        )}
145	      </>
146	    );
147	  }
148	
149	  private getBulkSelector(): JSX.Element {
150	    const selectedNamespaces = this.filteredSelected();
151	    const numSelected = selectedNamespaces.length;
152	    const allSelected = numSelected === this.props.namespaces.length;
153	    const anySelected = numSelected > 0;
154	    const someChecked = anySelected ? null : false;
155	    const isChecked = allSelected ? true : someChecked;
156	
157	    return (
158	      <div className={optionBulkStyle}>
159	        <Checkbox
160	          id="bulk-select-id"
161	          key="bulk-select-key"
162	          aria-label="Select all"
163	          isChecked={isChecked}
164	          onChange={() => {
165	            anySelected ? this.onBulkNone() : this.onBulkAll();
166	          }}
167	        ></Checkbox>
168	        <span className={optionLabelStyle}>Select all</span>
169	      </div>
170	    );
171	  }
172	
173	  private getHeader(): JSX.Element {
174	    const hasFilter = !!this.props.filter;
175	
176	    return (
177	      <div className={headerStyle}>
178	        <span style={{ display: 'flex' }}>
179	          <TextInput
180	            aria-label="filter-namespace"
181	            type="text"
182	            name="namespace-filter"
183	            placeholder="Filter by Name..."
184	            value={this.props.filter}
185	            onChange={(_event, value: string) => this.onFilterChange(value)}
186	          />
187	          {hasFilter && (
188	            <Tooltip key="ot_clear_namespace_filter" position="top" content="Clear Filter by Name">
189	              <Button className={closeButtonStyle} onClick={this.clearFilter} isInline>
190	                <KialiIcon.Close />
191	              </Button>
192	            </Tooltip>
193	          )}
194	        </span>
195	        {this.getBulkSelector()}
196	        <Divider className={dividerStyle} />
197	      </div>
198	    );
199	  }
200	
201	  private getBody(): JSX.Element {
202	    if (this.props.namespaces.length > 0) {
203	      const selectedMap = this.state.selectedNamespaces.reduce((map, namespace) => {
204	        map[namespace.name] = namespace.name;
205	        return map;
206	      }, {});
207	      const namespaces = this.filtered()
208	        .sort((a, b) => a.name.localeCompare(b.name))
209	        .map((namespace: Namespace) => (
210	          <div
211	            className={optionStyle}
212	            id={`namespace-list-item[${namespace.name}]`}
213	            key={`namespace-list-item[${namespace.name}]`}
214	          >
215	            <input
216	              type="checkbox"
217	              value={namespace.name}
218	              checked={!!selectedMap[namespace.name]}
219	              onChange={this.onNamespaceToggled}
220	            />
221	            <span className={optionLabelStyle}>{namespace.name}</span>
222	          </div>
223	        ));
224	
225	      return (
226	        <>
227	          <BoundingClientAwareComponent
228	            className={namespaceContainerStyle}
229	            maxHeight={{ type: PropertyType.VIEWPORT_HEIGHT_MINUS_TOP, margin: marginBottom }}
230	          >
231	            {namespaces}
232	          </BoundingClientAwareComponent>
233	        </>
234	      );
235	    }
236	    return <div className={optionStyle}>No namespaces found</div>;
237	  }
238	
239	  render(): JSX.Element {
240	    return (
241	      <TourStop info={GraphTourStops.Namespaces}>
242	        <Dropdown
243	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
244	            <MenuToggle
245	              ref={toggleRef}
246	              data-test="namespace-dropdown"
247	              id="namespace-selector"
248	              onClick={() => this.onToggle(!this.state.isOpen)}
249	              isExpanded={this.state.isOpen}
250	              isDisabled={this.props.disabled}
251	            >
252	              {this.namespaceButtonText()}
253	            </MenuToggle>
254	          )}
255	          isOpen={this.state.isOpen}
256	          onOpenChange={(isOpen: boolean) => this.onToggle(isOpen)}
257	        >
258	          <DropdownList>
259	            {this.getHeader()}
260	            {this.getBody()}
261	          </DropdownList>
262	        </Dropdown>
263	      </TourStop>
264	    );
265	  }
266	
267	  private onToggle = (isOpen: boolean): void => {
268	    if (isOpen) {
269	      this.props.refresh();
270	    } else {
271	      this.props.setActiveNamespaces(this.state.selectedNamespaces);
272	      this.clearFilter();
273	    }
274	    this.setState({
275	      isOpen
276	    });
277	  };
278	
279	  private onBulkAll = (): void => {
280	    const union = Array.from(new Set([...this.state.selectedNamespaces, ...this.filtered()]));
281	    this.setState({ selectedNamespaces: union });
282	  };
283	
284	  private onBulkNone = (): void => {
285	    const filtered = this.filtered();
286	    const remaining = this.state.selectedNamespaces.filter(s => filtered.findIndex(f => f.name === s.name) < 0);
287	    this.setState({ selectedNamespaces: remaining });
288	  };
289	
290	  onNamespaceToggled = (event): void => {
291	    const namespace = event.target.value;
292	    const selectedNamespaces = !!this.state.selectedNamespaces.find(n => n.name === namespace)
293	      ? this.state.selectedNamespaces.filter(n => n.name !== namespace)
294	      : this.state.selectedNamespaces.concat([{ name: event.target.value } as Namespace]);
295	    this.setState({ selectedNamespaces: selectedNamespaces });
296	  };
297	
298	  private onFilterChange = (value: string): void => {
299	    this.props.setFilter(value);
300	  };
301	
302	  private clearFilter = (): void => {
303	    this.props.setFilter('');
304	  };
305	
306	  private filtered = (): Namespace[] => {
307	    return this.props.namespaces.filter(ns => ns.name.toLowerCase().includes(this.props.filter.toLowerCase()));
308	  };
309	
310	  private filteredSelected = (): Namespace[] => {
311	    const filtered = this.filtered();
312	    return this.state.selectedNamespaces.filter(s => filtered.findIndex(f => f.name === s.name) >= 0);
313	  };
314	}
315	
316	const mapStateToProps = (state: KialiAppState): ReduxStateProps => {
317	  return {
318	    namespaces: namespaceItemsSelector(state)!,
319	    activeNamespaces: activeNamespacesSelector(state),
320	    filter: namespaceFilterSelector(state)
321	  };
322	};
323	
324	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => {
325	  return {
326	    refresh: () => {
327	      dispatch(NamespaceThunkActions.fetchNamespacesIfNeeded());
328	    },
329	    clearAll: () => {
330	      dispatch(NamespaceActions.setActiveNamespaces([]));
331	    },
332	    setActiveNamespaces: (namespaces: Namespace[]) => {
333	      dispatch(NamespaceActions.setActiveNamespaces(namespaces));
334	    },
335	    setFilter: (filter: string) => {
336	      dispatch(NamespaceActions.setFilter(filter));
337	    }
338	  };
339	};
340	
341	export const NamespaceDropdown = connect(mapStateToProps, mapDispatchToProps)(NamespaceDropdownComponent);

